  <div class="hud">
    <section class="panel title-panel">
      <h1>Snake: Together</h1>
      <ul>
        <li><strong>Space</strong> starts and restarts</li>
        <li><strong>Arrow keys</strong> steer your snake</li>
        <li>Bubblegum blue food grows +1</li>
        <li>Bubblegum pink super food grows +3</li>
      </ul>
    </section>
    <section class="panel status-panel">
      <p><strong>Status</strong></p>
      <div class="status-grid">
        <span class="label" id="label-local">You</span>
        <span class="value accent" id="score-local">0</span>
        <span class="label" id="label-remote">Friend</span>
        <span class="value" id="score-remote">--</span>
        <span class="label">Best</span>
        <span class="value" id="best">0</span>
        <span class="label">Stage</span>
        <span class="value" id="stage-name">Open Arena</span>
        <span class="label">Food</span>
        <span class="value super" id="food-type">Normal</span>
      </div>
    </section>
    <section class="panel message-panel"><p id="message">Press <strong>Space</strong> to start.</p></section>
    <section class="panel menu-panel hidden" id="menu-panel">
      <div class="menu-header"><h2>Start Menu</h2><p id="menu-note">Choose a mode, then launch the run.</p></div>
      <label class="menu-row"><span>Your Username</span><input id="username-input" maxlength="18" placeholder="Enter username" /></label>
      <label class="menu-row"><span>Stage Select</span><select id="stage-select"></select></label>
      <div class="menu-actions">
        <button class="menu-button primary" id="single-player-button">Single Player</button>
        <button class="menu-button" id="host-button">Host Game</button>
      </div>
      <div class="menu-join"><input id="join-code-input" maxlength="12" placeholder="Enter join code" /><button class="menu-button" id="join-button">Join</button></div>
      <section class="menu-lobby hidden" id="host-lobby">
        <p>Join code: <strong id="host-code">------</strong></p>
        <p id="lobby-status">Host a game to generate a code.</p>
        <button class="menu-button primary" id="start-match-button">Start Match</button>
      </section>
    </section>
    <button class="settings-button" id="settings-button" aria-label="Open settings">Settings</button>
    <section class="panel settings-panel hidden" id="settings-panel">
      <div class="settings-header"><h2>Settings</h2><button class="settings-close" id="settings-close" aria-label="Close settings">x</button></div>
      <div class="settings-section">
        <h3>Display</h3>
        <label class="settings-row"><span>Mode</span><select id="setting-display-mode"><option value="windowed">Windowed</option><option value="fullscreen">Fullscreen</option><option value="borderless">Borderless</option></select></label>
        <label class="settings-row"><span>FPS Counter</span><input type="checkbox" id="setting-show-fps" /></label>
        <label class="settings-row"><span>V-Sync</span><input type="checkbox" id="setting-vsync" /></label>
        <label class="settings-row"><span>FPS Cap</span><select id="setting-fps-cap"><option value="30">30</option><option value="60">60</option><option value="120">120</option><option value="unlimited">Unlimited</option></select></label>
      </div>
      <div class="settings-section">
        <h3>Graphics</h3>
        <label class="settings-row"><span>Renderer</span><select id="setting-renderer"><option value="webgl">Stable WebGL</option><option value="webgpu">WebGPU (Experimental)</option></select></label>
        <label class="settings-row"><span>DX12/WebGPU Path</span><input type="checkbox" id="setting-webgpu-toggle" /></label>
        <label class="settings-row"><span>Resolution Scale</span><select id="setting-resolution-scale"><option value="0.75">75%</option><option value="1">100%</option><option value="1.25">125%</option><option value="1.5">150%</option></select></label>
        <label class="settings-row"><span>DLSS Style</span><select id="setting-dlss-mode"><option value="off">Off</option><option value="quality">Quality</option><option value="balanced">Balanced</option><option value="performance">Performance</option></select></label>
        <label class="settings-row"><span>Shadow Quality</span><select id="setting-shadow-quality"><option value="off">Off</option><option value="low">Low</option><option value="high">High</option></select></label>
        <label class="settings-row"><span>Fog</span><input type="checkbox" id="setting-fog" /></label>
        <label class="settings-row"><span>RTX MODE</span><input type="checkbox" id="setting-fake-rtx" /></label>
      </div>
      <div class="settings-status">
        <p id="renderer-status">Renderer status: checking...</p>
        <p id="graphics-status">DLSS Style and RTX MODE are visual presets. WebGPU/DX12 needs support and may require restart.</p>
      </div>
      <p class="settings-note" id="settings-note">WebGPU and V-Sync changes may need a restart on some systems.</p>
      <button class="settings-save" id="settings-save">Save Settings</button>
    </section>
    <section class="panel fps-panel hidden" id="fps-panel"><p>FPS <span id="fps-value">0</span></p></section>
    <section class="intro-screen" id="intro-screen"><div class="panel intro-card"><h2 class="intro-title" id="intro-title">Snake: Together</h2><p class="intro-note" id="intro-note">Loading arena...</p></div></section>
  </div>
